var SPRACHBAUSTEINE = [
  // ── ARGUMENT INTRO ──
    { id:"sbs_001", cat:"argument_intro",
    sentence:{ de:"{{BLANK}} halte ich es für eine gute Idee, mehr Homeoffice-Tage einzuführen.", en:"{{BLANK}} I think introducing more home-office days is a good idea.", uk:"{{BLANK}} я вважаю впровадження більшої кількості домашніх днів гарною ідеєю.", ru:"{{BLANK}} я считаю внедрение большего количества домашних дней хорошей идеей." },
    answer:{ de:"Einerseits", en:"On the one hand", uk:"З одного боку", ru:"С одной стороны" },
    distractors:["Außerdem","Deshalb","Trotzdem","Jedoch","Meiner Ansicht nach"],
    explanation:{ de:"<b>„Einerseits“</b> eröffnet eine zweiseitige Argumentation (<b>„Einerseits“</b> … Andererseits).<br><b>„Außerdem“</b> ergänzt nur, bereitet kein Gegenargument vor.<br><b>„Deshalb“</b> drückt eine Folge aus, kein Abwägen.", en:"<b>„Einerseits“</b> opens a two-sided argument (<b>„Einerseits“</b> … Andererseits).<br><b>„Außerdem“</b> only adds information, it does not prepare a counterargument.<br><b>„Deshalb“</b> expresses a consequence, not a weighing.", uk:"<b>„Einerseits“</b> відкриває двосторонню аргументацію (<b>„Einerseits“</b> … Andererseits).<br><b>„Außerdem“</b> лише додає, але не готує контраргумент.<br><b>„Deshalb“</b> виражає наслідок, а не зважування.", ru:"<b>„С одной стороны“</b> открывает двустороннюю аргументацию (<b>„С одной стороны“</b> … С другой стороны).<br><b>„Кроме того“</b> только дополняет, но не готовит контраргумент.<br><b>„Поэтому“</b> выражает следствие, а не взвешивание." }
  },
  { id:"sbs_002", cat:"argument_intro",
    sentence:{ de:"{{BLANK}} bin ich der Meinung, dass flexible Arbeitszeiten die Produktivität steigern.", en:"{{BLANK}} I am of the opinion that flexible working hours increase productivity.", uk:"{{BLANK}} я вважаю, що гнучкий робочий час підвищує продуктивність.", ru:"{{BLANK}} я считаю, что гибкий рабочий график повышает продуктивность." },
    answer:{ de:"Grundsätzlich", en:"In principle", uk:"В принципі", ru:"В принципе" },
    distractors:["Einerseits","Im Großen und Ganzen","Trotz allem","Nichtsdestotrotz"],
    explanation:{ de:"<b>„Grundsätzlich“</b> signalisiert eine allgemeine, grundlegende Position.<br><b>„Einerseits“</b> erwartet ein <b>„Andererseits“</b>.<br><b>„Im Großen und Ganzen“</b> fasst bereits Gesagtes zusammen.", en:"<b>„Grundsätzlich“</b> signals a general, fundamental position.<br><b>„Einerseits“</b> expects an <b>„Andererseits“</b>.<br><b>„Im Großen und Ganzen“</b> summarises what has already been said.", uk:"<b>„Grundsätzlich“</b> сигналізує загальну, принципову позицію.<br><b>„Einerseits“</b> очікує <b>„Andererseits“</b>.<br><b>„Im Großen und Ganzen“</b> підсумовує вже сказане.", ru:"<b>„В принципе“</b> сигнализирует об общей, принципиальной позиции.<br><b>„С одной стороны“</b> ожидает <b>„С другой стороны“</b>.<br><b>„В общем и целом“</b> подытоживает уже сказанное." }
  },
  { id:"sbs_003", cat:"argument_intro",
    sentence:{ de:"{{BLANK}} spreche ich mich für eine Verlängerung der Elternzeit aus.", en:"{{BLANK}} I advocate for an extension of parental leave.", uk:"{{BLANK}} я виступаю за продовження відпустки по догляду за дитиною.", ru:"{{BLANK}} я выступаю за продление отпуска по уходу за ребенком." },
    answer:{ de:"Ausdrücklich", en:"Explicitly", uk:"Виразно", ru:"Категорически" },
    distractors:["Selbstverständlich","Grundsätzlich","Im Übrigen","Dennoch"],
    explanation:{ de:"<b>„Ausdrücklich“</b> betont Deutlichkeit und Entschlossenheit.<br><b>„Selbstverständlich“</b> klingt zu selbstverständlich.<br><b>„Im Übrigen“</b> leitet einen zusätzlichen Punkt ein, keine Positionierung.", en:"<b>„Ausdrücklich“</b> emphasises clarity and determination.<br><b>„Selbstverständlich“</b> sounds too self-evident.<br><b>„Im Übrigen“</b> introduces an additional point, not a stance.", uk:"<b>„Ausdrücklich“</b> підкреслює чіткість і рішучість.<br><b>„Selbstverständlich“</b> звучить занадто само собою зрозуміло.<br><b>„Im Übrigen“</b> вводить додатковий пункт, а не позицію.", ru:"<b>„Категорически“</b> подчеркивает четкость и решительность.<br><b>„Само собой разумеется“</b> звучит слишком очевидно.<br><b>„Впрочем“</b> вводит дополнительный пункт, а не позицию." }
  },
  { id:"sbs_004", cat:"argument_intro",
    sentence:{ de:"{{BLANK}} den gestiegenen Energiekosten sind many Haushalte stark belastet.", en:"{{BLANK}} rising energy costs, many households are heavily burdened.", uk:"{{BLANK}} зростання витрат на енергію багато домогосподарств зазнає значного навантаження.", ru:"{{BLANK}} из-за роста расходов на энергию многие домохозяйства несут сильную нагрузку." },
    answer:{ de:"Aufgrund", en:"Due to", uk:"На підставі", ru:"На основании" },
    distractors:["Wegen","Trotz","Angesichts","Infolge"],
    explanation:{ de:"<b>„Aufgrund + Genitiv“</b> ist im förmlichen Schriftdeutsch am gebräuchlichsten.<br>„Im Prüfungskontext wird es gegenüber dem umgangssprachlicheren <b>„Wegen“</b> bevorzugt.", en:"<b>„Aufgrund + Genitiv“</b> is most common in formal written German.<br>„In exam contexts it is preferred over the more colloquial <b>„Wegen“</b>.", uk:"<b>„Aufgrund + Genitiv“</b> є найпоширенішим у офіційному письмовому мовленні.<br>„На іспиті воно перевагує перед розмовнішим <b>„Wegen“</b>.", ru:"Конструкция <b>„Aufgrund + родительный падеж“</b> наиболее употребительна в официальном письменном немецком.<br>В контексте экзамена она предпочтительнее более разговорного <b>„Wegen“</b>." }
  },
  { id:"sbs_005", cat:"argument_intro",
    sentence:{ de:"{{BLANK}} möchte ich betonen, dass Weiterbildung ein wichtiger Faktor ist.", en:"{{BLANK}} I would like to emphasise that further training is an important factor.", uk:"{{BLANK}} хочу наголосити, що підвищення кваліфікації є важливим чинником.", ru:"{{BLANK}} хочу подчеркнуть, что повышение квалификации является важным фактором." },
    answer:{ de:"In diesem Zusammenhang", en:"In this context", uk:"У цьому контексті", ru:"В этой связи" },
    distractors:["In diesem Sinne","An dieser Stelle","Darüber hinaus","Dabei"],
    explanation:{ de:"<b>„In diesem Zusammenhang“</b> verweist auf den thematischen Kontext des Vorherigen.<br><b>„An dieser Stelle“</b> ist räumlich/zeitlich.<br><b>„Darüber hinaus“</b> fügt hinzu, knüpft aber nicht an den Kontext an.", en:"<b>„In diesem Zusammenhang“</b> refers to the thematic context of what preceded.<br><b>„An dieser Stelle“</b> is spatial/temporal.<br><b>„Darüber hinaus“</b> adds information but does not link to the context.", uk:"<b>„In diesem Zusammenhang“</b> посилається на тематичний контекст попереднього.<br><b>„An dieser Stelle“</b> є просторовим/часовим.<br><b>„Darüber hinaus“</b> додає, але не прив'язується до контексту.", ru:"<b>„В этой связи“</b> отсылает к тематическому контексту предыдущего.<br><b>„На данном этапе“</b> имеет пространственное или временное значение.<br><b>„Кроме того“</b> добавляет информацию, но не связывает с контекстом." }
  },
  { id:"sbs_006", cat:"argument_intro",
    sentence:{ de:"{{BLANK}} der aktuellen Entwicklungen ist Handlungsbedarf gegeben.", en:"{{BLANK}} current developments, action is required.", uk:"{{BLANK}} поточні події існує необхідність вжити заходів.", ru:"{{BLANK}} ввиду текущих событий существует необходимость принять меры." },
    answer:{ de:"Angesichts", en:"In view of", uk:"Зважаючи на", ru:"Ввиду" },
    distractors:["Aufgrund","Wegen","Infolge","Hinsichtlich"],
    explanation:{ de:"<b>„Angesichts + Genitiv“</b> bedeutet <b>„in Anbetracht, im Blick auf“</b>.<br><b>„Aufgrund“</b> wäre kausal.<br><b>„Hinsichtlich“</b> bedeutet <b>„was X betrifft“</b> — thematisch, nicht bewertend.", en:"<b>„Angesichts + Genitiv“</b> means <b>„in view of, considering“</b>.<br><b>„Aufgrund“</b> would be causal.<br><b>„Hinsichtlich“</b> means <b>„regarding X“</b> — thematic, not evaluative.", uk:"<b>„Angesichts + Genitiv“</b> означає <b>„з огляду на, беручи до уваги“</b>.<br><b>„Aufgrund“</b> було б причинним.<br><b>„Hinsichtlich“</b> означає <b>„що стосується X“</b> — тематично, не оцінювально.", ru:"Конструкция <b>„Angesichts + родительный падеж“</b> означает <b>„ввиду, принимая во внимание“</b>.<br><b>„Aufgrund“</b> указывало бы на причинно-следственную связь.<br><b>„Hinsichtlich“</b> означает <b>„что касается X“</b> — это тематическое, а не оценочное выражение." }
  },
  // ── COUNTER ARGUMENT ──
    { id:"sbs_007", cat:"counter_argument",
    sentence:{ de:"{{BLANK}} gibt es auch Menschen, die Online-Meetings als weniger effektiv empfinden.", en:"{{BLANK}} there are also people who find online meetings less effective.", uk:"{{BLANK}} є й люди, які вважають онлайн-наради менш ефективними.", ru:"{{BLANK}} есть и люди, которые считают онлайн-совещания менее эффективными." },
    answer:{ de:"Andererseits", en:"On the one hand", uk:"З іншого боку", ru:"С другой стороны" },
    distractors:["Einerseits","Außerdem","Daher","Folglich"],
    explanation:{ de:"<b>„Andererseits“</b> ist das klassische Gegenstück zu <b>„Einerseits“</b> und leitet das Gegenargument ein.<br><b>„Außerdem“</b> würde nur ergänzen.<br><b>„Daher / Folglich“</b> sind Folge-Konnektoren.", en:"<b>„Andererseits“</b> is the classic counterpart to <b>„Einerseits“</b> introducing the counterargument.<br><b>„Außerdem“</b> would only add.<br><b>„Daher / Folglich“</b> are consequence connectors.", uk:"<b>„Andererseits“</b> є класичним протиставленням до <b>„Einerseits“</b> і вводить контраргумент.<br><b>„Außerdem“</b> лише доповнює.<br><b>„Daher / Folglich“</b> — сполучники наслідку.", ru:"<b>„С другой стороны“</b> является классической противоположностью к <b>„С одной стороны“</b> и вводит контраргумент.<br><b>„Кроме того“</b> только дополняет.<br><b>„Поэтому / Следовательно“</b> — союзы следствия." }
  },
  { id:"sbs_008", cat:"counter_argument",
    sentence:{ de:"{{BLANK}} der Vorteile bleibt die hohe Kostenbelastung ein ernstes Problem.", en:"{{BLANK}} the advantages, the high financial burden remains a serious problem.", uk:"{{BLANK}} переваги, висока фінансова навантаженість залишается серйозною проблемою.", ru:"{{BLANK}} преимущества, высокая финансовая нагрузка остается серьезной проблемой." },
    answer:{ de:"Trotz", en:"Despite", uk:"Незважаючи на", ru:"Несмотря на" },
    distractors:["Wegen","Aufgrund","Angesichts","Infolge"],
    explanation:{ de:"<b>„Trotz + Genitiv“</b> drückt Konzession aus.<br><b>„Wegen / Aufgrund“</b> sind kausal.<br><b>„Angesichts“</b> bezieht sich auf Betrachtung, nicht Kontrast.", en:"<b>„Trotz + Genitiv“</b> expresses concession.<br><b>„Wegen / Aufgrund“</b> are causal.<br><b>„Angesichts“</b> relates to consideration, not contrast.", uk:"<b>„Trotz + Genitiv“</b> виражає поступку.<br><b>„Wegen / Aufgrund“</b> є причинними.<br><b>„Angesichts“</b> стосується розгляду, а не контрасту.", ru:"Конструкция <b>„Trotz + родительный падеж“</b> выражает уступку.<br><b>„Wegen / Aufgrund“</b> являются причинными.<br><b>„Angesichts“</b> относится к рассмотрению, а не к контрасту." }
  },
  { id:"sbs_009", cat:"counter_argument",
    sentence:{ de:"{{BLANK}} ist nicht zu leugnen, dass die Reform auch Risiken birgt.", en:"{{BLANK}} it cannot be denied that the reform also carries risks.", uk:"{{BLANK}} не можна заперечити, що реформа також несе ризики.", ru:"{{BLANK}} нельзя отрицать, что реформа также несет в себе риски." },
    answer:{ de:"Dennoch", en:"Neverthless", uk:"Проте", ru:"Тем не менее" },
    distractors:["Trotzdem","Nichtsdestotrotz","Allerdings","Jedoch"],
    explanation:{ de:"<b>„Dennoch“</b> leitet eine konzessive Aussage ein.<br><b>„Trotzdem“</b> ist umgangssprachlicher.<br><b>„Allerdings“</b> schränkt ein, aber ohne so starken Kontrast.", en:"<b>„Dennoch“</b> introduces a concessive statement.<br><b>„Trotzdem“</b> is more colloquial.<br><b>„Allerdings“</b> restricts but without as strong a contrast.", uk:"<b>„Dennoch“</b> вводить поступальне твердження.<br><b>„Trotzdem“</b> є розмовнішим.<br><b>„Allerdings“</b> обмежує, але без такого сильного контрасту.", ru:"<b>„Тем не менее“</b> вводит уступительное утверждение.<br><b>„Тут же“</b> (или Trotzdem) является более разговорным.<br><b>„Впрочем“</b> ограничивает, но без такого сильного контраста." }
  },
  { id:"sbs_010", cat:"counter_argument",
    sentence:{ de:"{{BLANK}} ist die Maßnahme umstritten, weil sie zu mehr Bürokratie führen kann.", en:"{{BLANK}} the measure is controversial because it may lead to more bureaucracy.", uk:"{{BLANK}} захід викликає суперечки, оскільки може призвести до більшої бюрократії.", ru:"{{BLANK}} мера вызывает споры, поскольку может привести к большей бюрократии." },
    answer:{ de:"Allerdings", en:"However", uk:"Однак", ru:"Однако" },
    distractors:["Dennoch","Hingegen","Jedoch","Gleichwohl"],
    explanation:{ de:"<b>„Allerdings“</b> schränkt eine vorherige positive Aussage ein.<br><b>„Hingegen“</b> stellt zwei Sachen direkt gegenüber.<br><b>„Allerdings“</b> klingt abwägender und ist im Prüfungsdeutsch gängiger.", en:"<b>„Allerdings“</b> restricts a previous positive statement.<br><b>„Hingegen“</b> directly contrasts two things.<br><b>„Allerdings“</b> sounds more balanced and is more common in exam German.", uk:"<b>„Allerdings“</b> обмежує попереднє позитивне твердження.<br><b>„Hingegen“</b> прямо протиставляє дві речі.<br><b>„Allerdings“</b> звучить зваженіше і є більш поширеним у мові іспитів.", ru:"<b>„Однако“</b> ограничивает предыдущее положительное утверждение.<br><b>„Напротив“</b> прямо противопоставляет две вещи.<br><b>„Однако“</b> звучит более взвешенно и чаще встречается на экзаменах." }
  },
  { id:"sbs_011", cat:"counter_argument",
    sentence:{ de:"Manche befürworten die Maßnahme — {{BLANK}} sehen darin eine Einschränkung.", en:"Some support the measure — {{BLANK}} see it as a restriction.", uk:"Одні підтримують захід — {{BLANK}} вбачають у ньому обмеження.", ru:"Одни поддерживают меру — {{BLANK}} видят в ней ограничение." },
    answer:{ de:"andere hingegen", en:"others however", uk:"інші натомість", ru:"другие же" },
    distractors:["andere jedoch","andere wiederum","einige trotzdem","manche dagegen"],
    explanation:{ de:"<b>„andere hingegen“</b> ist die feste Paarformel: Manche … andere hingegen.<br><b>„andere jedoch“</b> ist grammatisch richtig, aber weniger idiomatisch.", en:"<b>„andere hingegen“</b> is the set paired formula: Manche … andere hingegen.<br><b>„andere jedoch“</b> is grammatically correct but less idiomatic.", uk:"<b>„andere hingegen“</b> є усталеною парною формулою: Manche … andere hingegen.<br><b>„andere jedoch“</b> є граматично правильним, але менш ідіоматичним.", ru:"<b>„другие же“</b> (andere hingegen) — это устойчивая парная формула: Одни … другие же.<br>Вариант <b>„однако другие“</b> грамматически правилен, но менее идиоматичен." }
  },
  { id:"sbs_012", cat:"counter_argument",
    sentence:{ de:"{{BLANK}} den positiven Aspekten darf man die Nachteile nicht außer Acht lassen.", en:"{{BLANK}} the positive aspects, the disadvantages must not be ignored.", uk:"{{BLANK}} позитивними аспектами не можна ігнорувати недоліки.", ru:"{{BLANK}} положительными аспектами нельзя игнорировать недостатки." },
    answer:{ de:"Neben", en:"Alongside", uk:"Поряд з", ru:"Наряду с" },
    distractors:["Trotz","Außer","Zusätzlich zu","Angesichts"],
    explanation:{ de:"<b>„Neben + Dativ“</b> bedeutet <b>„zusätzlich zu“</b>.<br><b>„Trotz“</b> drückt Konzession aus.<br><b>„Außer“</b> bedeutet Ausschluss.", en:"<b>„Neben + Dativ“</b> means <b>„in addition to“</b>.<br><b>„Trotz“</b> expresses concession.<br><b>„Außer“</b> means exclusion.", uk:"<b>„Neben + Dativ“</b> означає <b>„на додачу до“</b>.<br><b>„Trotz“</b> виражає поступку.<br><b>„Außer“</b> означає виключення.", ru:"Конструкция <b>„Neben + дательный падеж“</b> означает <b>„в дополнение к“</b>.<br><b>„Trotz“</b> выражает уступку.<br><b>„Außer“</b> означает исключение." }
  },
  // ── OPINION ──
    { id:"sbs_013", cat:"opinion",
    sentence:{ de:"{{BLANK}} ist es wichtig, dass Unternehmen mehr in Nachhaltigkeit investieren.", en:"{{BLANK}} it is important that companies invest more in sustainability.", uk:"{{BLANK}} важливо, щоб підприємства більше інвестували у сталий розвиток.", ru:"{{BLANK}} важно, чтобы предприятия больше инвестировали в устойчивое развитие." },
    answer:{ de:"Meiner Meinung nach", en:"In my opinion", uk:"На мою думку", ru:"По моему мнению" },
    distractors:["Meiner Ansicht nach","Aus meiner Sicht","Meines Erachtens","Ich denke, dass"],
    explanation:{ de:"Alle vier drücken persönliche Meinung aus. Im DTB B2 sind <b>„Meiner Meinung nach“</b> und<br><b>„Meiner Ansicht nach“</b> am häufigsten getestet. Achten Sie auf korrekte Wortstellung.", en:"All four express personal opinion. In DTB B2, <b>„Meiner Meinung nach“</b> and<br><b>„Meiner Ansicht nach“</b> are tested most often. Pay attention to correct word order.", uk:"Усі чотири виражають особисту думку. На іспиті DTB B2 найчастіше перевіряються <b>„Meiner Meinung nach“</b> і<br><b>„Meiner Ansicht nach“</b>. Зверніть увагу на правильний порядок слів.", ru:"Все четыре выражения передают личное мнение. На экзамене DTB B2 чаще всего проверяются <b>„Meiner Meinung nach“</b> и<br><b>„Meiner Ansicht nach“</b>. Обратите внимание на правильный порядок слов." }
  },
  { id:"sbs_014", cat:"opinion",
    sentence:{ de:"{{BLANK}} überzeugt mich das Argument, weil es auf Fakten basiert.", en:"{{BLANK}} this argument convinces me because it is based on facts.", uk:"{{BLANK}} мене цей аргумент переконує, оскільки він ґрунтується на фактах.", ru:"{{BLANK}} меня этот аргумент убеждает, так как он основан на фактах." },
    answer:{ de:"Persönlich", en:"Personally", uk:"Особисто", ru:"Лично" },
    distractors:["Grundsätzlich","Eigentlich","Ehrlich gesagt","Im Wesentlichen"],
    explanation:{ de:"<b>„Persönlich“</b> betont die individuelle Haltung.<br><b>„Grundsätzlich“</b> ist zu allgemein.<br><b>„Eigentlich“</b> hätte eine konzessive Nuance.<br><b>„Ehrlich gesagt“</b> ist umgangssprachlicher.", en:"<b>„Persönlich“</b> emphasises the individual stance.<br><b>„Grundsätzlich“</b> is too general.<br><b>„Eigentlich“</b> would have a concessive nuance.<br><b>„Ehrlich gesagt“</b> is more colloquial.", uk:"<b>„Persönlich“</b> підкреслює індивідуальну позицію.<br><b>„Grundsätzlich“</b> є занадто загальним.<br><b>„Eigentlich“</b> мало б поступальний відтінок.<br><b>„Ehrlich gesagt“</b> є розмовнішим.", ru:"<b>„Лично“</b> (Persönlich) подчеркивает индивидуальную позицию.<br><b>„В принципе“</b> слишком обобщенно.<br><b>„Собственно говоря“</b> имело бы уступительный оттенок.<br><b>„Честно говоря“</b> — более разговорный вариант." }
  },
  { id:"sbs_015", cat:"opinion",
    sentence:{ de:"{{BLANK}} halte ich die vorgeschlagene Lösung für sinnvoll.", en:"{{BLANK}} I consider the proposed solution to be sensible.", uk:"{{BLANK}} я вважаю запропоноване рішення доцільним.", ru:"{{BLANK}} я считаю предложенное решение целесообразным." },
    answer:{ de:"Insgesamt", en:"Overall", uk:"Загалом", ru:"В целом" },
    distractors:["Grundsätzlich","Im Großen und Ganzen","Letztendlich","Prinzipiell"],
    explanation:{ de:"<b>„Insgesamt“</b> fasst eine abwägende Betrachtung zusammen.<br><b>„Im Großen und Ganzen“</b> ist sehr ähnlich, aber länger.<br><b>„Letztendlich“</b> fokussiert auf das Ergebnis.", en:"<b>„Insgesamt“</b> sums up a balanced consideration.<br><b>„Im Großen und Ganzen“</b> is very similar but longer.<br><b>„Letztendlich“</b> focuses on the outcome.", uk:"<b>„Insgesamt“</b> підсумовує зважений розгляд.<br><b>„Im Großen und Ganzen“</b> дуже схоже, але довше.<br><b>„Letztendlich“</b> фокусується на результаті.", ru:"<b>„В целом“</b> (Insgesamt) подытоживает взвешенное рассмотрение.<br><b>„В общем и целом“</b> очень похоже, но длиннее.<br><b>„В конечном итоге“</b> акцентирует внимание на результате." }
  },
  { id:"sbs_016", cat:"opinion",
    sentence:{ de:"{{BLANK}} bin ich zu dem Schluss gekommen, dass digitale Bildung zukunftsweisend ist.", en:"{{BLANK}} I have come to the conclusion that digital education is forward-looking.", uk:"{{BLANK}} я дійшов висновку, що цифрова освіта є перспективною.", ru:"{{BLANK}} я пришел к выводу, что цифровое образование является перспективным." },
    answer:{ de:"Letztendlich", en:"Ultimately", uk:"Зрештою", ru:"В конечном итоге" },
    distractors:["Schließlich","Am Ende","Insgesamt","Zusammenfassend"],
    explanation:{ de:"<b>„Letztendlich“</b> drückt ein endgültiges persönliches Urteil aus.<br><b>„Schließlich“</b> kann zeitlich sein.<br><b>„Insgesamt“</b> fasst zusammen, schließt aber kein persönliches Urteil ab.", en:"<b>„Letztendlich“</b> expresses a final personal judgement.<br><b>„Schließlich“</b> can be temporal.<br><b>„Insgesamt“</b> summarises but does not conclude with a personal verdict.", uk:"<b>„Letztendlich“</b> виражає остаточне особисте судження.<br><b>„Schließlich“</b> може бути часовим.<br><b>„Insgesamt“</b> підсумовує, але не завершує особистою оцінкою.", ru:"<b>„В конечном итоге“</b> (Letztendlich) выражает окончательное личное суждение.<br><b>„В конце концов“</b> может иметь временное значение.<br><b>„В общей сложности“</b> подытоживает, но не завершает личную оценку." }
  },
  // ── LETTER OPENING ──
    { id:"sbs_017", cat:"letter_opening",
    sentence:{ de:"{{BLANK}} Ihre Stellenausschreibung vom 15. März bewerbe ich mich hiermit um die ausgeschriebene Stelle.", en:"{{BLANK}} your job advertisement of 15 March I hereby apply for the advertised position.", uk:"{{BLANK}} ваше оголошення про вакансію від 15 березня цим листом подаю заявку на вказану посаду.", ru:"{{BLANK}} ваше объявление о вакансии от 15 марта настоящим письмом подаю заявку на указанную должность." },
    answer:{ de:"Auf", en:"In response to", uk:"На", ru:"На" },
    distractors:["Bezüglich","Hinsichtlich","Mit Blick auf","Im Hinblick auf"],
    explanation:{ de:"<b>„Auf + Akkusativ“</b> ist die feste Formulierung für Bewerbungen: <b>„Auf Ihre Ausschreibung …“</b>.<br><b>„Bezüglich / Hinsichtlich“</b> sind korrekt, aber für Anschreiben weniger idiomatisch.", en:"<b>„Auf + Akkusativ“</b> is the set phrasing for applications: <b>„Auf Ihre Ausschreibung …“</b>.<br><b>„Bezüglich / Hinsichtlich“</b> are correct but less idiomatic for cover letters.", uk:"<b>„Auf + Akkusativ“</b> є усталеним формулюванням для заяв: <b>„Auf Ihre Ausschreibung …“</b>.<br><b>„Bezüglich / Hinsichtlich“</b> правильні, але менш ідіоматичні для супровідних листів.", ru:"Конструкция <b>„Auf + винительный падеж“</b> — это устойчивое выражение для заявлений: <b>„На Ваше объявление …“</b>.<br>Варианты <b>„Bezüglich / Hinsichtlich“</b> правильны, но менее идиоматичны для сопроводительных писем." }
  },
  { id:"sbs_018", cat:"letter_opening",
    sentence:{ de:"{{BLANK}} Ihrer Anzeige in der Süddeutschen Zeitung wende ich mich an Sie.", en:"{{BLANK}} your advertisement in the Süddeutsche Zeitung I am writing to you.", uk:"{{BLANK}} Ваше оголошення в Süddeutsche Zeitung звертаюся до Вас.", ru:"{{BLANK}} Ваше объявление в Süddeutsche Zeitung обращаюсь к Вам." },
    answer:{ de:"Bezugnehmend auf", en:"With reference to", uk:"Посилаючись на", ru:"Ссылаясь на" },
    distractors:["Mit Bezug auf","In Bezug auf","Im Zusammenhang mit","Hinsichtlich"],
    explanation:{ de:"<b>„Bezugnehmend auf“</b> ist die klassische Einleitung für formelle Korrespondenz.<br><b>„In Bezug auf“</b> ist äquivalent, aber am Briefanfang weniger elegant.", en:"<b>„Bezugnehmend auf“</b> is the classic opening for formal correspondence.<br><b>„In Bezug auf“</b> is equivalent but less elegant at the start of a letter.", uk:"<b>„Bezugnehmend auf“</b> є класичним початком ділового листування.<br><b>„In Bezug auf“</b> є еквівалентом, але менш елегантним на початку листа.", ru:"<b>„Ссылаясь на“</b> (Bezugnehmend auf) — классическое начало для официальной переписки.<br>Вариант <b>„В отношении“</b> является эквивалентом, но выглядит менее элегантно в начале письма." }
  },
  { id:"sbs_019", cat:"letter_opening",
    sentence:{ de:"{{BLANK}} Ihr Schreiben vom 3. März teile ich Ihnen mit, dass wir Ihr Angebot annehmen.", en:"{{BLANK}} your letter of 3 March I inform you that we accept your offer.", uk:"{{BLANK}} Ваш лист від 3 березня повідомляю, що ми приймаємо Вашу пропозицію.", ru:"{{BLANK}} Ваш письмо от 3 марта сообщаю, что мы принимаем Ваше предложение." },
    answer:{ de:"In Antwort auf", en:"In reply to", uk:"У відповідь на", ru:"В ответ на" },
    distractors:["Als Antwort auf","Betreffend","Zu","Hiermit"],
    explanation:{ de:"<b>„In Antwort auf“</b> ist die förmliche Briefformel für Antwortschreiben.<br><b>„Als Antwort auf“</b> ist umgangssprachlicher.<br><b>„Betreffend“</b> leitet ein Thema ein, keine Antwort.", en:"<b>„In Antwort auf“</b> is the formal letter formula for a reply.<br><b>„Als Antwort auf“</b> is more colloquial.<br><b>„Betreffend“</b> introduces a topic, not a reply.", uk:"<b>„In Antwort auf“</b> є офіційною формулою для відповідного листа.<br><b>„Als Antwort auf“</b> є розмовнішим.<br><b>„Betreffend“</b> вводить тему, а не відповідь.", ru:"<b>„В ответ на“</b> (In Antwort auf) — официальная формулировка для ответного письма.<br>Вариант <b>„Как ответ на“</b> более разговорный.<br>Слово <b>„Касательно“</b> вводит тему, а не ответ." }
  },
  { id:"sbs_020", cat:"letter_opening",
    sentence:{ de:"{{BLANK}} habe ich Ihr Angebot sorgfältig geprüft und möchte Ihnen nun antworten.", en:"{{BLANK}} I have carefully reviewed your offer and would now like to respond.", uk:"{{BLANK}} я уважно розглянув(-ла) Вашу пропозицію і тепер хотів(-ла) б Вам відповісти.", ru:"{{BLANK}} я внимательно рассмотрел(-а) Ваше предложение и теперь хотел(-а) бы Вам ответить." },
    answer:{ de:"Mit großem Interesse", en:"With great interest", uk:"З великим інтересом", ru:"С большим интересом" },
    distractors:["Mit Interesse","Mit Freude","Mit Sorgfalt","Sehr gerne"],
    explanation:{ de:"<b>„Mit großem Interesse“</b> ist eine feste Formel für positive geschäftliche Korrespondenz.<br><b>„Mit Interesse“</b> ist kürzer, aber weniger emphatisch.<br><b>„Mit Freude“</b> klingt zu persönlich.", en:"<b>„Mit großem Interesse“</b> is a set formula for positive business correspondence.<br><b>„Mit Interesse“</b> is shorter but less emphatic.<br><b>„Mit Freude“</b> sounds too personal.", uk:"<b>„Mit großem Interesse“</b> є усталеною формулою для позитивного ділового листування.<br><b>„Mit Interesse“</b> коротше, але менш емфатичне.<br><b>„Mit Freude“</b> звучить занадто особисто.", ru:"<b>„С большим интересом“</b> — устойчивая формула для позитивной деловой переписки.<br>Вариант <b>„С интересом“</b> короче, но менее выразителен.<br><b>„С радостью“</b> звучит слишком лично." }
  },
  { id:"sbs_021", cat:"letter_opening",
    sentence:{ de:"{{BLANK}} nehme ich Bezug auf unser Telefonat vom gestrigen Tag.", en:"{{BLANK}} I refer to our telephone conversation of yesterday.", uk:"{{BLANK}} посилаюся на нашу телефонну розмову вчора.", ru:"{{BLANK}} ссылаюсь на наш вчерашний телефонный разговор." },
    answer:{ de:"Hiermit", en:"Hereby", uk:"Цим листом", ru:"Настоящим" },
    distractors:["Somit","Damit","Deshalb","Demnach"],
    explanation:{ de:"<b>„Hiermit“</b> ist ein typisches Eröffnungswort in deutschen Geschäftsbriefen — es verweist auf den aktuellen Schreibakt.<br><b>„Somit / Damit / Deshalb“</b> sind Folge-Konnektoren.", en:"<b>„Hiermit“</b> is a typical opening word in German business letters — it refers to the current act of writing.<br><b>„Somit / Damit / Deshalb“</b> are consequence connectors.", uk:"<b>„Hiermit“</b> є типовим вступним словом у німецьких ділових листах — воно вказує на поточний акт написання.<br><b>„Somit / Damit / Deshalb“</b> є сполучниками наслідку.", ru:"Слово <b>„Настоящим“</b> (Hiermit) — типичное вводное слово в немецких деловых письмах, оно указывает на сам акт написания письма.<br><b>„Таким образом / Тем самым / Поэтому“</b> являются союзами следствия." }
  },
  // ── LETTER CLOSING ──
    { id:"sbs_022", cat:"letter_closing",
    sentence:{ de:"{{BLANK}} stehe ich Ihnen für Rückfragen gerne zur Verfügung.", en:"{{BLANK}} I am happy to be available for any queries.", uk:"{{BLANK}} я радо відповім на Ваші запитання.", ru:"{{BLANK}} я с радостью отвечу на Ваши вопросы." },
    answer:{ de:"Bei Bedarf", en:"If needed", uk:"За потреби", ru:"При необходимости" },
    distractors:["Falls nötig","Wenn Sie möchten","Im Bedarfsfall","Sofern gewünscht"],
    explanation:{ de:"<b>„Bei Bedarf“</b> ist die idiomatische Briefformel.<br><b>„Im Bedarfsfall“</b> ist ein leichtes Synonym, aber seltener. Im Prüfungskontext ist <b>„Bei Bedarf“</b> am sichersten.", en:"<b>„Bei Bedarf“</b> is the idiomatic letter formula.<br><b>„Im Bedarfsfall“</b> is a slight synonym but rarer. In an exam context <b>„Bei Bedarf“</b> is the safest choice.", uk:"<b>„Bei Bedarf“</b> є ідіоматичною формулою листа.<br><b>„Im Bedarfsfall“</b> є незначним синонімом, але рідшим. На іспиті <b>„Bei Bedarf“</b> є найбезпечнішим.", ru:"Выражение <b>„Bei Bedarf“</b> — это идиоматическая формулировка для писем.<br><b>„Im Bedarfsfall“</b> является близким синонимом, но встречается реже. В контексте экзамена надежнее всего использовать <b>„Bei Bedarf“</b>." }
  },
  { id:"sbs_023", cat:"letter_closing",
    sentence:{ de:"Ich {{BLANK}} Sie bitten, mir die Unterlagen baldmöglichst zuzusenden.", en:"I {{BLANK}} ask you to send me the documents as soon as possible.", uk:"Я {{BLANK}} Вас попросити надіслати мені документи якнайшвидше.", ru:"Я {{BLANK}} Вас попросить выслать мне документы как можно скорее." },
    answer:{ de:"würde", en:"would", uk:"хотів би", ru:"хотел бы" },
    distractors:["möchte","werde","darf","kann"],
    explanation:{ de:"<b>„Ich würde Sie bitten“</b> ist der förmliche Konjunktiv II für höfliche Bitten.<br><b>„Ich möchte bitten“</b> ist umgangssprachlicher. Konjunktiv II signalisiert Höflichkeit.", en:"<b>„Ich würde Sie bitten“</b> is the formal Konjunktiv II for polite requests.<br><b>„Ich möchte bitten“</b> is more colloquial. Konjunktiv II signals politeness.", uk:"<b>„Ich würde Sie bitten“</b> — це офіційний Кон'юнктив II для ввічливих прохань.<br><b>„Ich möchte bitten“</b> є розмовнішим. Кон'юнктив II сигналізує ввічливість.", ru:"Фраза <b>„Ich würde Sie bitten“</b> — это официальное сослагательное наклонение (Konjunktiv II) для вежливых просьб.<br>Выражение <b>„Ich möchte bitten“</b> более разговорное. Конъюнктив II подчеркивает вежливость." }
  },
  { id:"sbs_024", cat:"letter_closing",
    sentence:{ de:"Für Rückfragen {{BLANK}} ich Ihnen gerne zur Verfügung.", en:"For any queries I am happy to {{BLANK}} at your disposal.", uk:"Für запитань я охоче {{BLANK}} до Ваших послуг.", ru:"Для вопросов я охотно {{BLANK}} к Вашим услугам." },
    answer:{ de:"stehe", en:"am available", uk:"перебуваю", ru:"нахожусь" },
    distractors:["bin","halte","bleibe","befinde"],
    explanation:{ de:"<b>„Zur Verfügung stehen“</b> ist die feste Redewendung für Hilfsbereitschaft.<br><b>„Zur Verfügung sein“</b> existiert nicht.<br><b>„Zur Verfügung halten“</b> bedeutet etwas bereithalten.", en:"<b>„Zur Verfügung stehen“</b> is the set phrase for readiness to help.<br><b>„Zur Verfügung sein“</b> does not exist.<br><b>„Zur Verfügung halten“</b> means to keep something ready.", uk:"<b>„Zur Verfügung stehen“</b> є усталеним виразом для готовності допомогти.<br><b>„Zur Verfügung sein“</b> не існує.<br><b>„Zur Verfügung halten“</b> означає тримати щось готовим.", ru:"<b>„Zur Verfügung stehen“</b> — это устойчивое выражение, означающее готовность помочь.<br>Варианта <b>„Zur Verfügung sein“</b> не существует.<br><b>„Zur Verfügung halten“</b> означает держать что-либо наготове." }
  },
  { id:"sbs_025", cat:"letter_closing",
    sentence:{ de:"Wir {{BLANK}}, Ihnen unser neues Angebot vorzustellen.", en:"We {{BLANK}} present our new offer to you.", uk:"Ми {{BLANK}} представити Вам нашу нову пропозицію.", ru:"Мы {{BLANK}} представить Вам наше новое предложение." },
    answer:{ de:"erlauben uns", en:"take the liberty to", uk:"дозволяємо собі", ru:"позволяем себе" },
    distractors:["gestatten uns","gönnen uns","nehmen uns die Freiheit","wagen es"],
    explanation:{ de:"<b>„Wir erlauben uns“</b> ist eine standardisierte höfliche Formel.<br><b>„Wir gestatten uns“</b> ist ein Synonym, aber seltener in modernem Geschäftsdeutsch.", en:"<b>„Wir erlauben uns“</b> is a standardised polite formula.<br><b>„Wir gestatten uns“</b> is a synonym but rarer in modern business German.", uk:"<b>„Wir erlauben uns“</b> є стандартизованою ввічливою формулою.<br><b>„Wir gestatten uns“</b> є синонімом, але рідшим у сучасній діловій мові.", ru:"Выражение <b>„Wir erlauben uns“</b> является стандартной вежливой формулой.<br><b>„Wir gestatten uns“</b> — синоним, но в современном деловом немецком языке он используется реже." }
  },
  { id:"sbs_026", cat:"letter_closing",
    sentence:{ de:"{{BLANK}} Ihren positiven Bescheid freuen wir uns sehr.", en:"{{BLANK}} your positive response we are very pleased.", uk:"{{BLANK}} Вашого позитивного рішення ми дуже раді.", ru:"{{BLANK}} Вашего положительного решения мы очень рады." },
    answer:{ de:"Über", en:"Over", uk:"З приводу", ru:"По поводу" },
    distractors:["Auf","Für","Mit","An"],
    explanation:{ de:"<b>„Sich freuen + über + Akkusativ“</b> ist die korrekte Präpositionalrektion.<br><b>„Sich freuen + auf + Akkusativ“</b> wäre für zukünftige Ereignisse. Hier bezieht es sich auf das Ergebnis.", en:"<b>„Sich freuen + über + Akkusativ“</b> is the correct prepositional government.<br><b>„Sich freuen + auf + Akkusativ“</b> would be for future events. Here it refers to the result.", uk:"<b>„Sich freuen + über + Akkusativ“</b> є правильним керуванням.<br><b>„Sich freuen + auf + Akkusativ“</b> було б для майбутніх подій. Тут мається на увазі результат.", ru:"Конструкция <b>„Sich freuen + über + Akkusativ“</b> является грамматически правильным управлением глагола.<br>Управление <b>„Sich freuen + auf + Akkusativ“</b> использовалось бы для будущих событий. В данном случае речь идет о готовом результате." }
  },
  // ── BUSINESS ──
    { id:"sbs_027", cat:"business",
    sentence:{ de:"Wir teilen Ihnen {{BLANK}} mit, dass Ihre Bestellung eingegangen ist.", en:"We {{BLANK}} inform you that your order has been received.", uk:"Ми {{BLANK}} повідомляємо Вас, що Ваше замовлення отримано.", ru:"Мы {{BLANK}} сообщаем Вам, что Ваш заказ получен." },
    answer:{ de:"hiermit", en:"hereby", uk:"цим", ru:"настоящим" },
    distractors:["somit","demnach","folglich","daher"],
    explanation:{ de:"<b>„Hiermit“</b> verweist auf den Akt des Schreibens selbst.<br><b>„Somit / Folglich“</b> sind Schlussfolgerungen.<br><b>„Demnach“</b> bedeutet „dem zufolge“.", en:"<b>„Hiermit“</b> refers to the act of writing itself.<br><b>„Somit / Folglich“</b> are logical conclusions.<br><b>„Demnach“</b> means „accordingly“.", uk:"<b>„Hiermit“</b> вказує на сам акт написання.<br><b>„Somit / Folglich“</b> є умовиводами.<br><b>„Demnach“</b> означає „відповідно до цього“.", ru:"Слово <b>„Настоящим“</b> (hiermit) указывает на сам акт написания письма.<br><b>„Таким образом / Следовательно“</b> являются выводами.<br><b>„Исходя из этого“</b> означает «согласно этому»." }
  },
  { id:"sbs_028", cat:"business",
    sentence:{ de:"Wir {{BLANK}} Sie, die Rechnung innerhalb von 14 Tagen zu begleichen.", en:"We {{BLANK}} you to settle the invoice within 14 days.", uk:"Ми {{BLANK}} Вас оплатити рахунок протягом 14 днів.", ru:"Мы {{BLANK}} Вас оплатить счет в течение 14 дней." },
    answer:{ de:"bitten", en:"ask", uk:"просимо", ru:"просим" },
    distractors:["fordern","verlangen","ersuchen","auffordern"],
    explanation:{ de:"<b>„Wir bitten Sie“</b> ist die standardmäßig höfliche Formulierung.<br><b>„Ersuchen“</b> ist förmlicher, häufiger in Behördensprache.<br><b>„Fordern / Verlangen“</b> klingen zu autoritär.", en:"<b>„Wir bitten Sie“</b> is the standard polite phrasing.<br><b>„Ersuchen“</b> is more formal, common in official language.<br><b>„Fordern / Verlangen“</b> sound too authoritative.", uk:"<b>„Wir bitten Sie“</b> є стандартним ввічливим формулюванням.<br><b>„Ersuchen“</b> є офіційнішим, частіше у мові держорганів.<br><b>„Fordern / Verlangen“</b> звучать занадто владно.", ru:"Фраза <b>„Wir bitten Sie“</b> является стандартной вежливой формулировкой.<br>Слово <b>„Ersuchen“</b> более официальное, чаще встречается в языке госорганов.<br><b>„Fordern / Verlangen“</b> звучат слишком авторитарно." }
  },
  { id:"sbs_029", cat:"business",
    sentence:{ de:"{{BLANK}} unserer bisherigen Zusammenarbeit freuen wir uns auf eine weitere Kooperation.", en:"{{BLANK}} our previous cooperation we look forward to further collaboration.", uk:"{{BLANK}} нашої попередньої співпраці ми раді продовжити кооперацію.", ru:"{{BLANK}} нашего предыдущего сотрудничества мы рады продолжить кооперацию." },
    answer:{ de:"Aufgrund", en:"Due to", uk:"На підставі", ru:"На основании" },
    distractors:["Angesichts","Infolge","Wegen","Dank"],
    explanation:{ de:"<b>„Aufgrund“</b> drückt Kausalität aus.<br><b>„Dank“</b> wäre auch positiv und möglich.<br><b>„Angesichts“</b> ist eher für kritische Situationen.<br><b>„Infolge“</b> betont Folgen, nicht Motivationen.", en:"<b>„Aufgrund“</b> expresses causality.<br><b>„Dank“</b> would also be positive and possible.<br><b>„Angesichts“</b> is more for critical situations.<br><b>„Infolge“</b> emphasises consequences, not motivations.", uk:"<b>„Aufgrund“</b> виражає причинність.<br><b>„Dank“</b> також було б позитивним і можливим.<br><b>„Angesichts“</b> скоріше для критичних ситуацій.<br><b>„Infolge“</b> підкреслює наслідки, а не мотиви.", ru:"Предлог <b>„Aufgrund“</b> выражает причинность.<br>Слово <b>„Dank“</b> (Благодаря) также было бы позитивным и возможным вариантом.<br><b>„Angesichts“</b> скорее подходит для критических ситуаций.<br><b>„Infolge“</b> подчеркивает последствия, а не мотивы." }
  },
  { id:"sbs_030", cat:"business",
    sentence:{ de:"Wir sind {{BLANK}}, Ihnen ein Sonderangebot zu unterbreiten.", en:"We are {{BLANK}} to present you with a special offer.", uk:"Ми {{BLANK}}, запропонувати Вам спеціальну пропозицію.", ru:"Мы {{BLANK}}, предложить Вам специальное предложение." },
    answer:{ de:"in der Lage", en:"able", uk:"в змозі", ru:"в состоянии" },
    distractors:["imstande","fähig","bereit","in der Position"],
    explanation:{ de:"<b>„In der Lage sein“</b> ist der förmliche Ausdruck für Fähigkeit.<br><b>„Imstande sein“</b> ist ein direktes Synonym, aber <b>„in der Lage“</b> ist im Schriftdeutsch häufiger.", en:"<b>„In der Lage sein“</b> is the formal expression for ability.<br><b>„Imstande sein“</b> is a direct synonym but <b>„in der Lage“</b> is more frequent in written German.", uk:"<b>„In der Lage sein“</b> є офіційним виразом здатності.<br><b>„Imstande sein“</b> є прямим синонімом, але <b>„in der Lage“</b> є частішим у письмовій мові.", ru:"Выражение <b>„In der Lage sein“</b> — это официальное выражение способности что-то сделать.<br><b>„Imstande sein“</b> является прямым синонимом, но <b>„in der Lage“</b> чаще встречается в письменной речи." }
  },
  { id:"sbs_031", cat:"business",
    sentence:{ de:"Bitte teilen Sie uns {{BLANK}} mit, ob Sie an unserem Angebot interessiert sind.", en:"Please let us know {{BLANK}} whether you are interested in our offer.", uk:"Будь ласка, повідомте нас {{BLANK}}, чи зацікавлені Ви нашою пропозицією.", ru:"Пожалуйста, сообщите нам {{BLANK}}, заинтересованы ли Вы в нашем предложении." },
    answer:{ de:"baldmöglichst", en:"as soon as possible", uk:"якнайшвидше", ru:"как можно скорее" },
    distractors:["schnellstmöglich","so bald wie möglich","zeitnah","umgehend"],
    explanation:{ de:"<b>„Baldmöglichst“</b> ist der klassische Ausdruck im Geschäftsdeutsch.<br><b>„Zeitnah“</b> ist modern und akzeptabel.<br><b>„Umgehend“</b> klingt dringlicher.", en:"<b>„Baldmöglichst“</b> is the classic expression in business German.<br><b>„Zeitnah“</b> is modern and acceptable.<br><b>„Umgehend“</b> sounds more urgent.", uk:"<b>„Baldmöglichst“</b> є класичним виразом у діловій мові.<br><b>„Zeitnah“</b> є сучасним і прийнятним.<br><b>„Umgehend“</b> звучить більш терміново.", ru:"Слово <b>„Baldmöglichst“</b> является классическим выражением в деловом немецком.<br><b>„Zeitnah“</b> — современный и приемлемый вариант.<br><b>„Umgehend“</b> звучит более срочно." }
  },
  { id:"sbs_032", cat:"business",
    sentence:{ de:"Wir {{BLANK}} uns über eine Bestätigung Ihrerseits.", en:"We {{BLANK}} a confirmation from your side.", uk:"Ми {{BLANK}} отримати підтвердження з Вашого боку.", ru:"Мы {{BLANK}} получить подтверждение с Вашей стороны." },
    answer:{ de:"würden uns freuen", en:"would be pleased", uk:"були б раді", ru:"были бы рады" },
    distractors:["freuen uns","werden uns freuen","hätten uns gefreut","erfreuen uns"],
    explanation:{ de:"<b>„Würden uns freuen“</b> (Konjunktiv II) ist die höfliche Briefformel.<br><b>„Freuen uns“</b> wäre Indikativ — zu direkt. Konjunktiv II signalisiert Höflichkeit.", en:"<b>„Würden uns freuen“</b> (Konjunktiv II) is the polite letter formula.<br><b>„Freuen uns“</b> would be Indicative — too direct. Konjunktiv II signals politeness.", uk:"<b>„Würden uns freuen“</b> (Кон'юнктив II) є ввічливою формулою листа.<br><b>„Freuen uns“</b> було б Індикативом — занадто прямо. Кон'юнктив II сигналізує ввічливість.", ru:"Конструкция <b>„Würden uns freuen“</b> (сослагательное наклонение Konjunktiv II) — это вежливая формулировка для писем.<br>Форма <b>„Freuen uns“</b> была бы изъявительным наклонением (излишне прямолинейно). Konjunktiv II подчеркивает вежливость." }
  },
  // ── CONCESSION ──
    { id:"sbs_033", cat:"concession",
    sentence:{ de:"{{BLANK}} die Kosten hoch sind, lohnt sich die Investition langfristig.", en:"{{BLANK}} the costs are high, the investment pays off in the long term.", uk:"{{BLANK}} витрати високі, інвестиція окупається в довгостроковій перспективі.", ru:"{{BLANK}} затраты высоки, инвестиция окупается в долгосрочной перспективе." },
    answer:{ de:"Obwohl", en:"Although", uk:"Хоча", ru:"Хотя" },
    distractors:["Obgleich","Wenngleich","Auch wenn","Selbst wenn"],
    explanation:{ de:"Alle vier sind konzessiv. <b>„Obwohl“</b> + Nebensatz ist am gebräuchlichsten.<br><b>„Obgleich / Wenngleich“</b> sind veraltet. Im DTB B2 ist <b>„Obwohl“</b> die sicherste Wahl.", en:"All four are concessive. <b>„Obwohl“</b> + subordinate clause is most common.<br><b>„Obgleich / Wenngleich“</b> are archaic. In DTB B2 <b>„Obwohl“</b> is the safest choice.", uk:"Всі чотири є поступальними. <b>„Obwohl“</b> + підрядне речення є найпоширенішим.<br><b>„Obgleich / Wenngleich“</b> є застарілими. На DTB B2 <b>„Obwohl“</b> є найбезпечнішим вибором.", ru:"Все четыре союза являются уступительными. Конструкция <b>„Obwohl“</b> + придаточное предложение наиболее употребительна.<br>Союзы <b>„Obgleich / Wenngleich“</b> устарели. На экзамене DTB B2 союз <b>„Obwohl“</b> — самый надежный выбор." }
  },
  { id:"sbs_034", cat:"concession",
    sentence:{ de:"{{BLANK}} aller Kritik hat sich das Projekt als Erfolg erwiesen.", en:"{{BLANK}} all criticism, the project proved to be a success.", uk:"{{BLANK}} всю критику проект виявився успішним.", ru:"{{BLANK}} всю критику проект оказался успешным." },
    answer:{ de:"Trotz", en:"Despite", uk:"Незважаючи на", ru:"Несмотря на" },
    distractors:["Wegen","Aufgrund","Angesichts","Durch"],
    explanation:{ de:"<b>„Trotz + Genitiv“</b> drückt Konzession aus: obwohl Kritik vorhanden war.<br><b>„Wegen / Aufgrund“</b> sind kausal.<br><b>„Angesichts“</b> ist für Konfrontation, weniger für positives Ergebnis.", en:"<b>„Trotz + Genitiv“</b> expresses concession: despite the criticism being present.<br><b>„Wegen / Aufgrund“</b> are causal.<br><b>„Angesichts“</b> is for confrontation, less for a positive result.", uk:"<b>„Trotz + Genitiv“</b> виражає поступку: хоча критика була наявна.<br><b>„Wegen / Aufgrund“</b> є причинними.<br><b>„Angesichts“</b> для конфронтації, менше для позитивного результату.", ru:"Конструкция <b>„Trotz + родительный падеж“</b> выражает уступку: вопреки тому, что была критика.<br><b>„Wegen / Aufgrund“</b> являются причинными.<br><b>„Angesichts“</b> указывает на то, что ситуация принимается во внимание, и реже используется для подведения позитивного итога." }
  },
  { id:"sbs_035", cat:"concession",
    sentence:{ de:"Ich verstehe Ihre Bedenken, {{BLANK}} möchte ich dennoch für meine Position werben.", en:"I understand your concerns, {{BLANK}} I would still like to advocate for my position.", uk:"Я розумію Ваші сумніви, {{BLANK}} хотів би відстояти свою позицію.", ru:"Я понимаю Ваши сомнения, {{BLANK}} хотел бы отстоять свою позицию." },
    answer:{ de:"jedoch", en:"however", uk:"проте", ru:"однако" },
    distractors:["dennoch","trotzdem","allerdings","gleichwohl"],
    explanation:{ de:"<b>„Jedoch“</b> leitet den Kontrastsatz ein ohne so stark zu sein wie <b>„Dennoch“</b>.<br><b>„Trotzdem“</b> ist umgangssprachlicher.<br><b>„Allerdings“</b> schränkt die vorherige Aussage ein.", en:"<b>„Jedoch“</b> introduces the contrasting clause without being as strong as <b>„Dennoch“</b>.<br><b>„Trotzdem“</b> is more colloquial.<br><b>„Allerdings“</b> restricts the previous statement.", uk:"<b>„Jedoch“</b> вводить контрастне речення, не будучи таким сильним, як <b>„Dennoch“</b>.<br><b>„Trotzdem“</b> є розмовнішим.<br><b>„Allerdings“</b> обмежує попереднє твердження.", ru:"Союз <b>„Jedoch“</b> вводит противопоставление, но выражает его не так резко, как <b>„Dennoch“</b>.<br>Слово <b>„Trotzdem“</b> более разговорное.<br><b>„Allerdings“</b> лишь частично ограничивает предыдущее утверждение." }
  },
  { id:"sbs_046", cat:"concession",
    sentence:{ de:"{{BLANK}} ich die Kritik verstehe, teile ich sie nicht vollständig.", en:"{{BLANK}} I understand the criticism, I do not share it entirely.", uk:"{{BLANK}} я розумію критику, я не поділяю її повністю.", ru:"{{BLANK}} я понимаю критику, я не разделяю её полностью." },
    answer:{ de:"Auch wenn", en:"Even though", uk:"Хоча", ru:"Даже если" },
    distractors:["Obwohl","Obgleich","Wenngleich","Selbst wenn"],
    explanation:{ de:"<b>„Auch wenn“</b> + Indikativ ist hier korrekt — man räumt ein, versteht die Kritik, teilt sie aber nicht. Im Prüfungskontext: prüfen Sie ob Konjunktiv oder Indikativ folgt.", en:"<b>„Auch wenn“</b> + Indicative is correct here — one concedes understanding the criticism but does not share it. In exam contexts check whether Konjunktiv or Indicative follows.", uk:"<b>„Auch wenn“</b> + Індикатив тут правильний — визнаєш, розумієш критику, але не поділяєш її. На іспиті перевіряйте, чи слідує Кон'юнктив чи Індикатив.", ru:"Конструкция <b>„Auch wenn“</b> + изъявительное наклонение (Indikativ) здесь уместна: факт признается (критика понятна), но позиция не разделяется. В контексте экзамена: всегда проверяйте, какое наклонение следует далее — сослагательное или изъявительное." }
  },
  // ── COMPARISON ──
    { id:"sbs_036", cat:"comparison",
    sentence:{ de:"{{BLANK}} dem Vorjahr hat sich der Umsatz verdoppelt.", en:"{{BLANK}} the previous year, turnover has doubled.", uk:"{{BLANK}} попереднім роком обсяг продажів подвоївся.", ru:"{{BLANK}} прошлым годом оборот удвоился." },
    answer:{ de:"Im Vergleich zu", en:"Compared to", uk:"Порівняно з", ru:"По сравнению с" },
    distractors:["Gegenüber","Anders als","Im Gegensatz zu","Verglichen mit"],
    explanation:{ de:"<b>„Im Vergleich zu“</b> ist der neutralste vergleichende Ausdruck.<br><b>„Im Gegensatz zu“</b> betont stärker den Widerspruch.<br><b>„Gegenüber“</b> ist kürzer und auch korrekt.", en:"<b>„Im Vergleich zu“</b> is the most neutral comparative expression.<br><b>„Im Gegensatz zu“</b> emphasises the contrast more.<br><b>„Gegenüber“</b> is shorter and also correct.", uk:"<b>„Im Vergleich zu“</b> є найнейтральнішим порівняльним виразом.<br><b>„Im Gegensatz zu“</b> більше підкреслює протиріччя.<br><b>„Gegenüber“</b> коротше і теж правильне.", ru:"Выражение <b>„Im Vergleich zu“</b> является наиболее нейтральным для сравнения.<br><b>„Im Gegensatz zu“</b> сильнее подчеркивает противоречие.<br>Предлог <b>„Gegenüber“</b> короче и тоже правилен." }
  },
  { id:"sbs_037", cat:"comparison",
    sentence:{ de:"{{BLANK}} der alten Methode ist die neue deutlich effizienter.", en:"{{BLANK}} the old method, the new one is significantly more efficient.", uk:"{{BLANK}} старого методу новий є значно ефективнішим.", ru:"{{BLANK}} старого метода новый значительно более эффективен." },
    answer:{ de:"Im Gegensatz zu", en:"In contrast to", uk:"На відміну від", ru:"В отличие от" },
    distractors:["Im Vergleich zu","Gegenüber","Anders als","Statt"],
    explanation:{ de:"<b>„Im Gegensatz zu“</b> betont den Widerspruch/Kontrast.<br><b>„Im Vergleich zu“</b> ist neutraler.<br><b>„Statt“</b> bedeutet Ersatz, kein Kontrast.", en:"<b>„Im Gegensatz zu“</b> emphasises the contradiction/contrast.<br><b>„Im Vergleich zu“</b> is more neutral.<br><b>„Statt“</b> means replacement, not contrast.", uk:"<b>„Im Gegensatz zu“</b> підкреслює протиріччя/контраст.<br><b>„Im Vergleich zu“</b> є нейтральнішим.<br><b>„Statt“</b> означає заміну, а не контраст.", ru:"Выражение <b>„Im Gegensatz zu“</b> подчеркивает противоречие/контраст.<br><b>„Im Vergleich zu“</b> более нейтрально.<br>Предлог <b>„Statt“</b> означает замену, а не контраст." }
  },
  // ── CONSEQUENCE ──
    { id:"sbs_038", cat:"consequence",
    sentence:{ de:"{{BLANK}} lässt sich sagen, dass die Maßnahme erfolgreich war.", en:"{{BLANK}} it can be said that the measure was successful.", uk:"{{BLANK}} можна сказати, що захід виявився успішним.", ru:"{{BLANK}} можно сказать, что мера оказалась успешной." },
    answer:{ de:"Zusammenfassend", en:"In summary", uk:"Підсумовуючи", ru:"Подводя итог" },
    distractors:["Insgesamt","Abschließend","Resümierend","Letztendlich"],
    explanation:{ de:"<b>„Zusammenfassend“</b> leitet eine Schlussfolgerung ein.<br><b>„Abschließend“</b> bezieht sich auf den Abschluss der Rede.<br><b>„Insgesamt“</b> ist Fazit-Wort, aber kein typischer Satzeinleiter.", en:"<b>„Zusammenfassend“</b> introduces a conclusion.<br><b>„Abschließend“</b> relates to the close of a speech.<br><b>„Insgesamt“</b> is a summary word but not a typical sentence opener.", uk:"<b>„Zusammenfassend“</b> вводить висновок.<br><b>„Abschließend“</b> стосується завершення промови.<br><b>„Insgesamt“</b> є словом-підсумком, але не типовим початком речення.", ru:"<b>„Подводя итог“</b> (Zusammenfassend) вводит логический вывод.<br><b>„В заключение“</b> (Abschließend) относится к завершению речи.<br>Слово <b>„В общей сложности“</b> (Insgesamt) является итоговым, но не служит типичным началом предложения." }
  },
  { id:"sbs_039", cat:"consequence",
    sentence:{ de:"{{BLANK}} können wir festhalten, dass die Nachfrage gestiegen ist.", en:"{{BLANK}} we can note that demand has increased.", uk:"{{BLANK}} можемо констатувати, що попит зріс.", ru:"{{BLANK}} мы можем констатировать, что спрос вырос." },
    answer:{ de:"Abschließend", en:"In conclusion", uk:"На завершення", ru:"В заключение" },
    distractors:["Zusammenfassend","Insgesamt","Daher","Folglich"],
    explanation:{ de:"<b>„Abschließend“</b> signalisiert den letzten Punkt in einer Argumentation.<br><b>„Zusammenfassend“</b> fasst mehrere Punkte zusammen.<br><b>„Daher / Folglich“</b> drücken Kausalfolge aus.", en:"<b>„Abschließend“</b> signals the last point in an argument.<br><b>„Zusammenfassend“</b> summarises several points.<br><b>„Daher / Folglich“</b> express causal consequence.", uk:"<b>„Abschließend“</b> сигналізує останній пункт в аргументації.<br><b>„Zusammenfassend“</b> підсумовує кілька пунктів.<br><b>„Daher / Folglich“</b> виражають причинно-наслідковий зв'язок.", ru:"Слово <b>„В заключение“</b> (Abschließend) сигнализирует о последнем пункте в аргументации.<br><b>„Подводя итог“</b> (Zusammenfassend) обобщает несколько пунктов.<br><b>„Поэтому / Следовательно“</b> выражают причинно-следственную связь." }
  },
  { id:"sbs_040", cat:"consequence",
    sentence:{ de:"Der Lärmpegel ist zu hoch, {{BLANK}} sollten wir Maßnahmen ergreifen.", en:"The noise level is too high, {{BLANK}} we should take action.", uk:"Рівень шуму є занадто високим, {{BLANK}} нам слід вжити заходів.", ru:"Уровень шума слишком высок, {{BLANK}} нам следует принять меры." },
    answer:{ de:"daher", en:"therefore", uk:"тому", ru:"поэтому" },
    distractors:["folglich","somit","deshalb","infolgedessen"],
    explanation:{ de:"Alle fünf Adverbien drücken eine Konsequenz aus. <b>„Daher“</b> unterscheidet sich stilistisch, da es im geschriebenen Standarddeutsch formeller und eleganter wirkt als das alltagssprachlichere <b>„deshalb“</b> oder <b>„deswegen“</b>.", en:"All five adverbs express a consequence. <b>„Daher“</b> differs stylistically, as it sounds more formal and elegant in standard written German than the more colloquial <b>„deshalb“</b> or <b>„deswegen“</b>.", uk:"Усі п'ять прислівників виражають наслідок. <b>„Daher“</b> відрізняється стилістично, оскільки в письмовій літературній мові воно звучить офіційніше та елегантніше, ніж більш розмовні <b>„deshalb“</b> або <b>„deswegen“</b>.", ru:"Все пять наречий выражают следствие. <b>„Daher“</b> отличается стилистически, так как в письменном литературном языке оно звучит более официально и элегантно, чем более разговорные <b>„deshalb“</b> или <b>„deswegen“</b>." }
  },
  { id:"sbs_041", cat:"consequence",
    sentence:{ de:"Das Projekt ist gescheitert, {{BLANK}} müssen wir neue Wege suchen.", en:"The project has failed, {{BLANK}} we must seek new approaches.", uk:"Проект зазнав невдачі, {{BLANK}} нам потрібно шукати нові шляхи.", ru:"Проект потерпел неудачу, {{BLANK}} нам нужно искать новые пути." },
    answer:{ de:"folglich", en:"consequently", uk:"отже", ru:"следовательно" },
    distractors:["daher","somit","deshalb","infolgedessen"],
    explanation:{ de:"<b>„Folglich“</b> betont die logische Schlussfolgerung.<br><b>„Infolgedessen“</b> ist korrekt aber formeller und länger.<br><b>„Daher“</b> ist ein direktes Synonym<br>beide sind prüfungstauglich.", en:"<b>„Folglich“</b> emphasises the logical conclusion.<br><b>„Infolgedessen“</b> is correct but more formal and longer.<br><b>„Daher“</b> is a direct synonym<br>both are suitable for the exam.", uk:"<b>„Folglich“</b> підкреслює логічний висновок.<br><b>„Infolgedessen“</b> правильне, але офіційніше і довше.<br><b>„Daher“</b> є прямим синонімом<br>обидва підходять для іспиту.", ru:"Союз <b>„Folglich“</b> подчёркивает логическое заключение.<br>Слово <b>„Infolgedessen“</b> грамматически правильно, но является более официальным и длинным.<br><b>„Daher“</b> — прямой синоним,<br>оба варианта отлично подходят для экзамена." }
  },
  { id:"sbs_042", cat:"consequence",
    sentence:{ de:"{{BLANK}} der steigenden Nachfrage hat das Unternehmen seine Produktion ausgeweitet.", en:"{{BLANK}} rising demand the company has expanded its production.", uk:"{{BLANK}} зростаючого попиту підприємство розширило своє виробництво.", ru:"{{BLANK}} растущего спроса предприятие расширило свое производство." },
    answer:{ de:"Infolge", en:"As a result of", uk:"Внаслідок", ru:"Вследствие" },
    distractors:["Aufgrund","Wegen","Dank","Angesichts"],
    explanation:{ de:"<b>„Infolge + Genitiv“</b> drückt direkte Folge-Kausalität aus.<br><b>„Aufgrund“</b> ist ähnlich, aber allgemeiner.<br><b>„Dank“</b> hat positive Konnotation.<br><b>„Angesichts“</b> ist für Konfrontation.", en:"<b>„Infolge + Genitiv“</b> expresses direct consequential causality.<br><b>„Aufgrund“</b> is similar but more general.<br><b>„Dank“</b> has a positive connotation.<br><b>„Angesichts“</b> is for confrontation.", uk:"<b>„Infolge + Genitiv“</b> виражає пряму причинно-наслідкову каузальність.<br><b>„Aufgrund“</b> схоже, але загальніше.<br><b>„Dank“</b> має позитивне конотацію.<br><b>„Angesichts“</b> для конфронтації.", ru:"Конструкция <b>„Infolge + родительный падеж“</b> выражает прямую причинно-следственную связь.<br>Предлог <b>„Aufgrund“</b> близок по значению, но более универсален.<br>Слово <b>„Dank“</b> (Благодаря) имеет положительную коннотацию.<br>Предлог <b>„Angesichts“</b> (Ввиду) чаще используется в контексте назревающего вызова или проблемы." }
  },
  // ── ADDITIONAL ──
    { id:"sbs_043", cat:"argument_intro",
    sentence:{ de:"Die Umfrage zeigt, dass es {{BLANK}} ist, die Digitalisierung voranzutreiben.", en:"The survey shows that it is {{BLANK}} to drive digitalisation forward.", uk:"Опитування показує, що {{BLANK}} просувати цифровізацію.", ru:"Опрос показывает, что {{BLANK}} продвигать цифровизацию." },
    answer:{ de:"dringend erforderlich", en:"urgently necessary", uk:"вкрай необхідно", ru:"крайне необходимо" },
    distractors:["unbedingt nötig","absolut wichtig","sehr sinnvoll","äußerst hilfreich"],
    explanation:{ de:"<b>„Dringend erforderlich“</b> ist der standardisierte Ausdruck im Geschäftsdeutsch für notwendige Maßnahmen. Die anderen Varianten sind stilistisch weniger präzise.", en:"<b>„Dringend erforderlich“</b> is the standardised expression in business German for necessary measures. The other variants are stylistically less precise.", uk:"<b>„Dringend erforderlich“</b> є стандартизованим виразом у діловій мові для необхідних заходів. Інші варіанти є стилістично менш точними.", ru:"Выражение <b>„Dringend erforderlich“</b> является стандартизированным в деловом немецком языке для обозначения необходимых мер. Другие варианты стилистически менее точны." }
  },
  { id:"sbs_044", cat:"letter_opening",
    sentence:{ de:"{{BLANK}} Ihrer Stellenausschreibung vom 1. April bewerbe ich mich um die Position.", en:"{{BLANK}} your job advertisement of 1 April I apply for the position.", uk:"{{BLANK}} Ваше оголошення про вакансію від 1 квітня подаю заявку на посаду.", ru:"{{BLANK}} Ваше объявление о вакансии от 1 апреля подаю заявку на должность." },
    answer:{ de:"Bezugnehmend auf", en:"With reference to", uk:"Посилаючись на", ru:"Ссылаясь на" },
    distractors:["Auf","In Bezug auf","Hinsichtlich","Mit Bezug auf"],
    explanation:{ de:"<b>„Bezugnehmend auf“</b> ist die klassische förmliche Einleitung für Bewerbungsschreiben.<br><b>„Auf“</b> ist kürzer und auch idiomatisch. Beide sind im Prüfungskontext akzeptiert.", en:"<b>„Bezugnehmend auf“</b> is the classic formal opening for job applications.<br><b>„Auf“</b> is shorter and also idiomatic. Both are accepted in exam contexts.", uk:"<b>„Bezugnehmend auf“</b> є класичним офіційним вступом для заяв.<br><b>„Auf“</b> коротше і теж ідіоматичне. Обидва прийняті в контексті іспиту.", ru:"<b>„Bezugnehmend auf“</b> — классическое официальное вводное выражение для заявлений о приеме на работу.<br>Предлог <b>„Auf“</b> короче и также идиоматичен. Оба варианта признаются корректными." }
  },
  { id:"sbs_045", cat:"counter_argument",
    sentence:{ de:"{{BLANK}} zugegeben werden muss, dass die alten Lösungen Grenzen haben.", en:"{{BLANK}} it must be admitted that the old solutions have limitations.", uk:"{{BLANK}} треба визнати, що старі рішення мають обмеження.", ru:"{{BLANK}} надо признать, что старые решения имеют ограничения." },
    answer:{ de:"Auch wenn", en:"Even if", uk:"Навіть якщо", ru:"Даже если" },
    distractors:["Obwohl","Selbst wenn","Wenngleich","Trotzdem"],
    explanation:{ de:"<b>„Auch wenn“</b> drückt konzessive Hypothesen aus.<br><b>„Obwohl“</b> braucht keinen Konjunktiv.<br><b>„Selbst wenn“</b> ist emphatischer.<br><b>„Trotzdem“</b> ist ein Satzadverb, kein Subjunktor.", en:"<b>„Auch wenn“</b> expresses concessive hypotheses.<br><b>„Obwohl“</b> does not require Konjunktiv.<br><b>„Selbst wenn“</b> is more emphatic.<br><b>„Trotzdem“</b> is a sentence adverb, not a subjunctor.", uk:"<b>„Auch wenn“</b> виражає поступальні гіпотези.<br><b>„Obwohl“</b> не потребує Кон'юнктива.<br><b>„Selbst wenn“</b> є емфатичнішим.<br><b>„Trotzdem“</b> є прислівником, а не підрядним сполучником.", ru:"Союз <b>„Auch wenn“</b> выражает уступительные гипотезы.<br>Союз <b>„Obwohl“</b> не требует после себя сослагательного наклонения (Konjunktiv).<br><b>„Selbst wenn“</b> выражает уступку более эмфатически.<br>Слово <b>„Trotzdem“</b> является наречием, а не подчинительным союзом." }
  },
  { id:"sbs_047", cat:"business",
    sentence:{ de:"Wir {{BLANK}} Ihrer Antwort bis zum 30. Juni entgegen.", en:"We {{BLANK}} your reply by 30 June.", uk:"Ми з нетерпінням {{BLANK}} Вашої відповіді до 30 червня.", ru:"Мы с нетерпением {{BLANK}} Вашего ответа до 30 июня." },
    answer:{ de:"sehen", en:"look forward to", uk:"очікуємо", ru:"ожидаем" },
    distractors:["schauen","warten","erhoffen","erwarten"],
    explanation:{ de:"<b>„Entgegensehen“</b> (+ Dativ) ist die feste Formel: <b>„Wir sehen Ihrer Antwort entgegen.“</b><br><b>„Erwarten“</b> wäre auch grammatisch, aber weniger förmlich-idiomatisch in Briefschlüssen.", en:"<b>„Entgegensehen“</b> (+ Dative) is the set formula: <b>„Wir sehen Ihrer Antwort entgegen.“</b><br><b>„Erwarten“</b> would also be grammatical but less formally idiomatic in letter closings.", uk:"<b>„Entgegensehen“</b> (+ Dativ) є усталеною формулою: <b>„Wir sehen Ihrer Antwort entgegen.“</b><br><b>„Erwarten“</b> було б граматично правильним, але менш ідіоматичним у кінцівках листів.", ru:"Глагол <b>„Entgegensehen“</b> (+ дательный падеж) образует устойчивое выражение: <b>„Wir sehen Ihrer Antwort entgegen.“</b><br>Слово <b>„Erwarten“</b> также грамматически корректно, но звучит менее официально-идиоматично для концовки делового письма." }
  },
  { id:"sbs_048", cat:"opinion",
    sentence:{ de:"{{BLANK}} teile ich die Ansicht, dass mehr Investitionen nötig sind.", en:"{{BLANK}} I share the view that more investment is needed.", uk:"{{BLANK}} поділяю думку, що необхідні більші інвестиції.", ru:"{{BLANK}} разделяю мнение, что необходимы большие инвестиции." },
    answer:{ de:"Vollständig", en:"Completely", uk:"Повністю", ru:"Полностью" },
    distractors:["Grundsätzlich","Weitgehend","Ausdrücklich","Insgesamt"],
    explanation:{ de:"<b>„Vollständig teile ich“</b> bedeutet vollkommene Übereinstimmung.<br><b>„Weitgehend“</b> wäre eine teilweise Zustimmung.<br><b>„Grundsätzlich“</b> ist korrekt, aber schwächer.", en:"<b>„Vollständig teile ich“</b> means complete agreement.<br><b>„Weitgehend“</b> would be partial agreement.<br><b>„Grundsätzlich“</b> is correct but weaker.", uk:"<b>„Vollständig teile ich“</b> означає повну згоду.<br><b>„Weitgehend“</b> було б частковою згодою.<br><b>„Grundsätzlich“</b> правильне, але слабше.", ru:"Выражение <b>„Vollständig teile ich“</b> означает абсолютное согласие.<br>Слово <b>„Weitgehend“</b> означало бы согласие лишь в значительной степени.<br>Наречие <b>„Grundsätzlich“</b> грамматически подходит, но выражает менее сильную позицию." }
  },
];
